$.extend(true, $.fn.dataTable.Buttons.defaults, {
    dom: {
        button: {
            className: "",
        },
    },
});

$.ajaxSetup({
    headers: {
        "X-CSRF-TOKEN": $('meta[name="csrf-token"]').attr("content"),
    },
});

$(function () {
    // Add User
    $(document).on("submit", "#formAddUser", function (e) {
        e.preventDefault();
        let form = $(this);
        $.ajax({
            url: form.attr("action"),
            type: "POST",
            data: form.serialize(),
            success: function (res) {
                if (res.success) {
                    $("#modalAddUser").modal("hide");
                    $("#tableUserList").DataTable().ajax.reload();
                    Swal.fire("Sukses", res.message, "success");
                }
            },
            error: function (xhr) {
                Swal.fire(
                    "Error",
                    xhr.responseJSON?.message || "Terjadi kesalahan",
                    "error"
                );
            },
        });
    });

    // Update User
    $(document).on("submit", "#formEditUser", function (e) {
        e.preventDefault();
        let form = $(this);

        $.ajax({
            url: form.attr("action"),
            type: "POST", // tetap pakai POST karena ada _method PUT
            data: form.serialize(),
            success: function (res) {
                if (res.success) {
                    $("#modalEditUser").modal("hide");
                    $("#tableUserList").DataTable().ajax.reload();
                    Swal.fire("Sukses", res.message, "success");
                }
            },
            error: function (xhr) {
                Swal.fire(
                    "Error",
                    xhr.responseJSON.message || "Terjadi kesalahan",
                    "error"
                );
            },
        });
    });

    $(document).on(
        "click",
        '#tableUserList button[data-target="#modalEditUser"]',
        function () {
            let id = $(this).data("id");
            let url = window.routes.getUser.replace(":id", id);

            $.get(url, function (res) {
                let user = res.user;
                $("#formEditUser").attr("action", url);
                $("#edit_name").val(user.name);
                $("#edit_email").val(user.email);
                $("#edit_aktifasi").val(user.active ? "Aktif" : "Nonaktif");
                $("#edit_akses").val(user.role || "Aktif");
                $("#edit_password, #edit_password_confirmation").val("");
                if (user.profile) {
                    $("#edit_company").val(user.profile.pf_company || "");
                    $("#edit_wa").val(user.profile.pf_wa || "");
                    $("#edit_telegram").val(user.profile.pf_telegram || "");
                    $("#edit_address").val(user.profile.pf_address || "");
                } else {
                    $(
                        "#edit_company, #edit_wa, #edit_telegram, #edit_address"
                    ).val("");
                }
                $("#modalEdit").modal("show");
            });
        }
    );
});

/**
 * Objek global untuk mengelola fungsionalitas format.
 * Mengandung fungsi-fungsi helper untuk memformat data seperti tanggal dan angka.
 */
const FormatHelper = {
    /**
     * Memformat tanggal dari YYYY-MM-DD atau DD-MM-YYYY menjadi DD-MM-YYYY.
     *
     * @param {string} dateString String tanggal yang akan diformat.
     * @returns {string} Tanggal yang diformat atau string asli jika format tidak dikenali.
     */
    formatTanggal: function (dateString) {
        if (!dateString) return '';
        const dateParts = dateString.split('-');
        if (dateParts.length !== 3) return dateString;

        const [part1, part2, part3] = dateParts;
        const isYYYYMMDD = part1.length === 4 && part2.length === 2 && part3.length === 2;
        const isDDMMYYYY = part1.length === 2 && part2.length === 2 && part3.length === 4;

        if (isYYYYMMDD) {
            return `${part3}-${part2}-${part1}`;
        } else if (isDDMMYYYY) {
            return dateString; 
        } else {
            return dateString;
        }   
    },
}

const TableHelper = {
    dynamicTable: {
        ajax: window.routes.dataTable,
        paging: true,
        searching: true,
        ordering: true,
        info: true,
        autoWidth: false,
        responsive: true,
        processing: true,
        serverSide: false,
        order: [[1, "asc"]],
        columns: [
            {
                data: "id",
                className: "dt-head-center dt-body-center",
                title: "ID",
                orderable: true,
            },
            { 
                data: "name", 
                className: "dt-head-center", 
                title: "Nama User",
                orderable: true,
            },
            {
                data: "email",
                className: "dt-head-center",
                title: "Alamat Email",
            },
            {
                data: "status",
                className: "dt-head-center dt-body-center col-status",
                title: "Status",
                orderable: true,
            },
            {
                data: "role",
                className: "dt-head-center dt-body-center",
                title: "Hak Akses",
                orderable: true,
            },
            {
                data: "last_login_at",
                className: "dt-head-center dt-body-center",
                title: "Terakhir Aktif",
                render: (data, type) => TableHelper.tabelTanggalWaktu(data, type),
                orderable: false,
                searchable: false,
            },
            {
                data: "created_at",
                className: "dt-head-center dt-body-center",
                title: "Waktu Dibuat",
                render: (data, type) => TableHelper.tabelTanggalWaktu(data, type),
                orderable: false,
                searchable: false,
            },
            {
                data: "updated_at",
                className: "dt-head-center dt-body-center",
                title: "Waktu Diubah",
                render: (data, type) => TableHelper.tabelTanggalWaktu(data, type),
                orderable: false,
                searchable: false,
            },
            {
                data: "action",
                orderable: false,
                searchable: false,
                className: "dt-head-center dt-body-center",
                title: "Aksi",
            },
        ],
        dom: `
            <"row mb-2"<"col-sm-2"B><"col-sm-2"l><"col-sm-8"f>>
            <"row"<"col-sm-12"tr>>
            <"row mt-2"<"col-sm-5"i><"col-sm-7"p>>
        `,
        buttons: [
            {
                text: "Add",
                className: "dt-button btn btn-sm",
                attr: {
                    "data-target": "#modalAddUser",
                    "data-toggle": "modal",
                },
            },
            {
                text: "Excel",
                className: "dt-button btn btn-sm",
            },
        ],
    },

    /**
     * Fungsi render untuk kolom Tanggal dan Waktu di DataTables.
     * Bergantung pada fungsi formatTanggal dari FormatHelper.
     * Contoh penggunaan: { targets: [6, 7], render: TabelHelper.tabelTanggalWaktu }
     */
    tabelTanggalWaktu: function (data, type) {
        if (!data) return "-";
        if (type !== "display") return data;
        const [tanggal, waktu] = data.split(" ");
        const formattedTanggal = FormatHelper.formatTanggal(tanggal);
        return `${formattedTanggal} → ${waktu || ""}`;
    },
};

$("#tableUserList").DataTable(TableHelper.dynamicTable);